class Solution:
    def minSpaceWastedKResizing(self, nums, k):
        import sys
        n = len(nums)
        # cost[i][j] = waste of one segment covering indices i..j inclusive
        cost = [[0] * n for _ in range(n)]
        for i in range(n):
            mx = 0
            tot = 0
            for j in range(i, n):
                mx = max(mx, nums[j])
                tot += nums[j]
                cost[i][j] = mx * (j - i + 1) - tot
        INF = float('inf')
        # dp recursion: best(start, segs) = min waste covering start..n-1 with at most segs segments
        from functools import lru_cache
        import sys as _sys
        _sys.setrecursionlimit(10000)
        memo = {}
        def best(start, segs):
            if start == n:
                return 0
            if segs == 0:
                return INF
            key = (start, segs)
            if key in memo:
                return memo[key]
            ans = INF
            for end in range(start, n):
                rest = best(end + 1, segs - 1)
                if rest < INF:
                    ans = min(ans, cost[start][end] + rest)
            memo[key] = ans
            return ans
        return best(0, k + 1)

