class Solution:
    def minSpaceWastedKResizing(self, nums, k):
        n = len(nums)
        k += 1  # number of segments allowed
        cost = [[0] * n for _ in range(n)]
        for i in range(n):
            mx = 0
            tot = 0
            for j in range(i, n):
                if nums[j] > mx:
                    mx = nums[j]
                tot += nums[j]
                cost[i][j] = mx * (j - i + 1) - tot
        INF = float('inf')
        # dp[c][i] = min waste for prefix of length i using c segments
        dp = [[INF] * (n + 1) for _ in range(k + 1)]
        dp[0][0] = 0
        for c in range(1, k + 1):
            for i in range(1, n + 1):
                for p in range(c - 1, i):
                    if dp[c - 1][p] < INF:
                        cand = dp[c - 1][p] + cost[p][i - 1]
                        if cand < dp[c][i]:
                            dp[c][i] = cand
        return min(dp[c][n] for c in range(1, k + 1))

