var minSpaceWastedKResizing = function(nums, k) {
    const n = nums.length;
    const segs = k + 1;
    const cost = Array.from({length: n}, () => new Array(n).fill(0));
    for (let i = 0; i < n; i++) {
        let mx = 0, tot = 0;
        for (let j = i; j < n; j++) {
            if (nums[j] > mx) mx = nums[j];
            tot += nums[j];
            cost[i][j] = mx * (j - i + 1) - tot;
        }
    }
    const INF = Infinity;
    const dp = Array.from({length: segs + 1}, () => new Array(n + 1).fill(INF));
    dp[0][0] = 0;
    for (let c = 1; c <= segs; c++) {
        for (let i = 1; i <= n; i++) {
            for (let p = c - 1; p < i; p++) {
                if (dp[c - 1][p] < INF) {
                    const cand = dp[c - 1][p] + cost[p][i - 1];
                    if (cand < dp[c][i]) dp[c][i] = cand;
                }
            }
        }
    }
    let ans = INF;
    for (let c = 1; c <= segs; c++) ans = Math.min(ans, dp[c][n]);
    return ans;
};
